<template>
    <div class="container">
        <h1>Tabla carrito de compras</h1>
        <table>
            <thead>
                <tr>
                    <th>Codigo</th>
                    <th>Cantidad</th>                    
                    <th>Producto</th>
                    <th>Eliminar</th>
                </tr>
            </thead>
            <tbody>

                <tr v-for="carrito in carritos" :key="carrito.codigo">
                    <td>{{ carrito.codigo }}</td>
                    <td>{{ carrito.cantidadProductos }}</td>
                    <td>{{ carrito.productos?.nombre }}</td>
                    <td><div><button class="btnEliminar" @click="$emit('eliminar', carrito.codigo)">Eliminar</button></div></td>
                </tr>
            </tbody>
        </table>
    </div>
</template>
<script>
import axios from 'axios';
export default{
    data(){
        return{
            carritos:[],

        };
    },
    methods:{
        obtenerCarritos(){
            axios.get("https://proyecto5-production-7426.up.railway.app/api/carrito/listar")
            .then((response)=>{

                this.carritos=response.data;

            })
            .catch((error)=>{
                console.error("error al obtener la lista carrito",error)
            });
        },
    },

    mounted(){
        this.obtenerCarritos();
    }
}

</script>