<template>

    <div class="container">

        <h1>Formulario de Productos</h1>

        <form id="formulario-productos" action="" @submit.prevent="guardar">

            <div class="form-group">

                <label for="">Codigo</label>
                <input type="text" id="codigo" name="codigo" required v-model="codigo"/>

            </div>
            <div class="form-group">

                <label for="">Nombre</label>
                <input type="text" id="nombre" name="nombre" required v-model="nombre"/>

            </div>
            <div class="form-group">

                <label for="">Categoria</label>
                <input type="text" id="Categoria" name="Categoria" required v-model="categoria"/>

            </div>
            <div class="form-group">

                <label for="">Descripcion</label>
                <input type="text" id="descripcion" name="descripcion" required v-model="descripcion"/>

            </div>
            <div class="form-group">

                <label for="">Marca</label>
                <input type="text" id="marca" name="marca" required v-model="marca"/>

            </div>
            <div class="form-group">

                <label for="">Precio</label>
                <input type="text" id="precio" name="precio" required v-model="precio"/>

            </div>

            <button type="submit">Guardar</button>
            <button type="button" @click="eliminar">Eliminar</button>
            <button type="button" @click="actualizar">Actualizar</button>
            <button type="button" @click="consultar">Consultar</button>
            <button type="button" @click="limpiarFormulario">Limpiar</button>

        </form>

    </div>

</template>

<script>

    import axios from 'axios';   

    export default{

        data(){

            return{
                
            codigo:"",
            nombre:"",
            categoria:"",
            descripcion:"",
            marca:"",
            precio:"",
        };    

        },

            methods:{

                guardar(){

                    axios.post("https://proyecto5-production-7426.up.railway.app/api/productos",{

                        codigo: this.codigo,
                        nombre: this.nombre,
                        categoria: this.categoria,
                        descripcion: this.descripcion,
                        marca: this.marca,
                        precio: this.precio,

                    })
                    .then((response)=>{

                    console.log("Producto registrado con exito",response.data);
                    alert("El producto se registro correctamente")
                    this.codigo=""
                    this.categoria=""
                    this.descripcion=""
                    this.marca=""
                    this.precio=""
                    this.$emit("actualizar-tabla");
                })

                .catch((error)=>{
                    console.error("Error al registrar el producto",error);
                    alert("Registro fallido")

                });

                },

                consultar(){

                    axios.get("https://proyecto5-production-7426.up.railway.app/api/productos/"+this.codigo)
                    .then((response)=>{

                        this.nombre=response.data.nombre;
                        this.categoria=response.data.categoria;
                        this.descripcion=response.data.descripcion;
                        this.marca=response.data.marca;
                        this.precio=response.data.precio;
                    })
                    .catch((error)=>{

                        console.error("Error al consultar los productos",error);

                    });

                },
                actualizar(){

                    axios.put("https://proyecto5-production-7426.up.railway.app/api/productos/actualizar/"+this.codigo,{

                        codigo:this.codigo,
                        nombre:this.nombre,
                        categoria:this.categoria,
                        descripcion:this.descripcion,
                        marca:this.marca,
                        precio:this.precio,
                                       
                    })
                    .then((response)=>{
                        console.log("Producto actualizado con existo",response.data)
                        alert("Producto actualizado con exito");
                        this.$emit("actualizar-tabla");
                    
                    })
                    .catch((error)=>{
                        console.error("Error al registar el producto",error)

                    });
                
                },
                eliminar(){

                    axios.delete("https://proyecto5-production-7426.up.railway.app/api/productos/"+this.codigo,)
                    .then(()=>{
                        
                        alert("Producto eliminado con exito");
                        this.codigo="";
                        this.nombre="";
                        this.categoria="";
                        this.descripcion="";
                        this.marca="";
                        this.precio="";
                        this.$emit("actualizar-tabla");
                    })
                    .catch((error)=>{
                        console.error("Fallo al eliminar el producto",error);

                    })

                },
                limpiarFormulario(){

                        this.codigo="";
                        this.nombre="";
                        this.categoria="";
                        this.descripcion="";
                        this.marca="";
                        this.precio="";

                },

            },
            
    
    }

</script>

