<template>
    <div class="container">
        <h1>Inventario</h1>

        <form id="formulario-inventario" @submit.prevent="guardar">

            <div class="form-group">
                <label for="codigo">Código Inventario</label>
                <input type="text" id="codigo" v-model="codigo" placeholder="ID del inventario">
            </div>
            <div class="form-group">
                <label for="productos">Producto</label>
                <select id="productos" class="select" required v-model="producto">
                    <option value="">Seleccione un producto</option>
                    <option v-for="p in listaProductos" :key="p.codigo" :value="p.codigo">
                        {{ p.nombre }}
                    </option>
                </select>
            </div>

            <div class="form-group">

                <label for="cantidadProductos">Cantidad</label>
                <input type="text" id="cantidadProductos" name="cantidadProductos" required v-model="cantidad">

            </div>           
            <button type="button" @click="actualizar">Actualizar</button>
            <button type="button" @click="consultar">Consultar</button>
            <button type="button" @click="limpiarFormulario">Limpiar</button>

        </form>
    </div>
</template>
<script>
import axios from 'axios';
export default{
    data(){

        return{
        codigo: "",
        cantidad:"",
        producto:"",
        listaProductos: []
    };         

    },

        methods:{

            cargarProductos() {
            axios.get("https://proyecto5-production-7426.up.railway.app/api/productos/listar")
                .then(response => {
                        this.listaProductos = response.data;
                })
                .catch(error => {
                        console.error("Error al cargar los productos", error);
                });
            },


            consultar(){

                axios.get("https://proyecto5-production-7426.up.railway.app/api/inventario/"+this.codigo)
                .then((response)=>{

                    this.cantidad=response.data.cantidad;
                    this.producto=response.data.productos.codigo;
                })
                .catch((error)=>{

                    console.error("Error al consultar los productos",error);
                    });
                },
            actualizar(){

                axios.put("https://proyecto5-production-7426.up.railway.app/api/inventario/actualizar/"+this.codigo,{

                    cantidad: this.cantidad,
                    productos: { codigo: this.producto },
                                       
                })
                .then((response)=>{
                    console.log("Producto actualizado con existo",response.data)
                    alert("Producto actualizado con exito");
                    this.$emit("actualizar-tabla");
                    
                })
                .catch((error)=>{
                    console.error("Error al registar el producto",error)

                });
                
            },
            eliminar(){

                axios.delete("https://proyecto5-production-7426.up.railway.app/api/inventario/"+this.codigo,)
                .then(()=>{
                        
                    alert("Producto eliminado con exito");
                    this.cantidad="";
                    this.producto="";
                    this.$emit("actualizar-tabla");
                })
                .catch((error)=>{
                    console.error("Fallo al eliminar el producto",error);

                })

            },
            limpiarFormulario(){
                    this.codigo=""
                    this.cantidad="";
                    this.producto="";

            }
            

        },
        mounted(){
            this.cargarProductos();

        }
}

</script>