<template>
    <div class="container">
        <h1>Formulario carrito de compras</h1>

        <form id="formulario-carrito" @submit.prevent="guardar">

            <div class="form-group">
                <label for="codigo">Código Carrito</label>
                <input type="text" id="codigo" v-model="codigo" placeholder="ID del producto">
            </div>
            <div class="form-group">
                <label for="productos">Seleccione un producto</label>
                <select id="productos" class="select" required v-model="productoSeleccionado">
                    <option value="">Seleccione un producto</option>
                    <option v-for="p in listaProductos" :key="p.codigo" :value="p.codigo">
                        {{ p.nombre }}
                    </option>
                </select>
            </div>

            <div class="form-group">

                <label for="cantidadProductos">Cantidad</label>
                <input type="text" id="cantidadProductos" name="cantidadProductos" required v-model="cantidadProductos">

            </div>   
            <button type="button" @click="guardar">Agregar</button>        
            <button type="button" @click="actualizar">Actualizar</button>
            <button type="button" @click="consultar">Consultar</button>
            <button type="button" @click="limpiarFormulario">Limpiar</button>

        </form>
    </div>
</template>
<script>
import axios from 'axios';
export default{
    data(){

        return{
        codigo: "",
        cantidadProductos:"",
        producto:"",
        productoSeleccionado:"",
        listaProductos: []
    };         

    },

        methods:{

            cargarProductos() {
            axios.get("https://proyecto5-production-7426.up.railway.app/api/productos/listar")
                .then(response => {
                        this.listaProductos = response.data;
                })
                .catch(error => {
                        console.error("Error al cargar los productos", error);
                });
            },
            guardar(){
                this.producto = this.productoSeleccionado;
                axios.post("https://proyecto5-production-7426.up.railway.app/api/carrito",{

                    codigo: this.codigo,
                    cantidadProductos: this.cantidadProductos,
                    productos: { codigo: this.productos }

                })
                .then((response)=>{

                console.log("Producto registrado con exito",response.data);
                alert("El producto se registro correctamente")
                this.codigo=""
                this.cantidadProductos=""
                this.productos=""
                this.$emit("actualizar-tabla");
            })

            .catch((error)=>{
                console.error("Error al registrar el producto",error);
                alert("Registro fallido")

            });

            },


            consultar(){

                axios.get("https://proyecto5-production-7426.up.railway.app/api/carrito/"+this.codigo)
                .then((response)=>{
                    this.codigo=response.data.codigo
                    this.cantidadProductos=response.data.cantidadProductos;
                    this.productos=response.data.productos.codigo;
                })
                .catch((error)=>{

                    console.error("Error al consultar los productos",error);
                    });
                },
            actualizar(){
                this.productos = this.productoSeleccionado;
                axios.put("https://proyecto5-production-7426.up.railway.app/api/carrito/actualizar/"+this.codigo,{
                    
                    codigo: this.codigo,
                    cantidadProductos: this.cantidadProductos,
                    productos: { codigo: this.productos },
                                       
                })
                .then((response)=>{
                    console.log("Producto actualizado con existo",response.data)
                    alert("Producto actualizado con exito");
                    this.$emit("actualizar-tabla");
                    
                })
                .catch((error)=>{
                    console.error("Error al registar el producto",error)

                });
                
            },
            eliminar(){

                axios.delete("https://proyecto5-production-7426.up.railway.app/api/carrito/"+this.codigo,)
                .then(()=>{
                        
                    alert("Producto eliminado con exito");
                    this.codigo="";
                    this.cantidadProductos="";
                    this.productos="";
                    this.$emit("actualizar-tabla");
                })
                .catch((error)=>{
                    console.error("Fallo al eliminar el producto",error);

                })

            },
            limpiarFormulario(){
                    this.codigo=""
                    this.cantidadProductos="";
                    this.productos="";
                    this.productoSeleccionado ="";

            }
            

        },
        mounted(){
            this.cargarProductos();

        },
}

</script>

