<template>

    <div class="container">

        <h1>Tabla productos</h1>

        <table>

            <thead>

                <tr>
                    <th>Codigo</th>
                    <th>Nombre</th>
                    <th>Categoria</th>
                    <th>Descripcion</th>
                    <th>Marca</th>
                    <th>Precio</th>
                </tr>
                 
                
            </thead>
            <tbody>
                <tr v-for="producto in productos" :key="producto.codigo">
                    <td>{{producto.codigo}}</td>
                    <td>{{producto.nombre}}</td>
                    <td>{{producto.categoria}}</td>
                    <td>{{producto.descripcion}}</td>
                    <td>{{producto.marca}}</td>
                    <td>{{producto.precio}}</td>
                </tr>

            </tbody>


        </table>

    </div>



</template>

<script>

import axios from 'axios';

export default{
    data(){

        return{

            productos:[],

        };
  
    },
    methods:{

        obtenerProductos(){

            axios.get("https://proyecto5-production-7426.up.railway.app/api/productos/listar")
            .then((response)=>{

                this.productos=response.data;

            })
            .catch((error)=>{

                console.error("Error al obtener los productos",error);

            });

        }
    } ,   

    mounted(){

        this.obtenerProductos();

    },

    

}

</script>