<template>
    <div class="inventario">
        <div class="components">
            <FormularioInventario @actualizar-tabla="actualizarTabla"/>
            <TablaInventario ref="tablaInventarios" @eliminar="eliminarInventario"/>
        </div>  
    </div>
</template>
<script>
import axios from 'axios';
import FormularioInventario from '@/components/FormularioInventario.vue';
import TablaInventario from '@/components/TablaInventario.vue';
    
export default{
    name:'InventarioView',
        components:{
            FormularioInventario,
            TablaInventario
        },

        methods:{
            actualizarTabla(){
                this.$refs.tablaInventarios.obtenerInventarios();
            },
            eliminarInventario(codeInv) {
                if(!confirm("¿Estas seguro de eliminar este producto del inventario?")) return;
                axios.delete("http://localhost:8080/api/inventario/" + codeInv)
                    .then(() => {
                        alert("Producto eliminado con éxito");
                        this.actualizarTabla();
                    })
                    .catch(error => {
                        console.error("Fallo al eliminar el producto", error);
                        alert("No se pudo eliminar el producto");
                    });
            }
        }
}

</script>
