<template>
    <div class="carritoDeCompras">

        <div class="components">
            
            <FormularioCarrito @actualizar-tabla="actualizarTabla"/>
            <TablaCarrito ref="tablaCarrito" @eliminar="eliminarCarrito"/>
            

        </div>

    </div>

</template>

<script>
    import axios from 'axios';
    import FormularioCarrito from '@/components/FormularioCarrito.vue';
    import TablaCarrito from '@/components/TablaCarrito.vue';

    export default{
        name:'carritoView',
        components:{
            FormularioCarrito,
            TablaCarrito
        },
        methods:{
                actualizarTabla(){
                    this.$refs.tablaCarrito.obtenerCarritos();
                },
                eliminarCarrito(codigo) {
                    if(!confirm("¿Estas seguro de eliminar este producto del carrito?")) return;
                    axios.delete("http://localhost:8080/api/carrito/" + codigo)
                        .then(() => {
                            alert("Producto eliminado con éxito");
                            this.actualizarTabla();
                        })
                        .catch(error => {
                            console.error("Fallo al eliminar el producto", error);
                            alert("No se pudo eliminar el producto");
                        });
                }
            }
        
    }

</script>

