<template>
    <div class="container">
        <h1>Tabla inventario</h1>
        <table>
            <thead>
                <tr>
                    <th>Codigo</th>
                    <th>Fecha de creacion</th>
                    <th>Cantidad disponible</th>
                    <th>Producto</th>
                    <th>Eliminar</th>
                </tr>
            </thead>
            <tbody>

                <tr v-for="inventario in inventarios" :key="inventario.codeInv">
                    <td>{{ inventario.codeInv }}</td>
                    <td>{{ inventario.fechaCrea }}</td>
                    <td>{{ inventario.cantidad }}</td>
                    <td>{{ inventario.productos.nombre }}</td>
                    <td><div><button class="btnEliminar" @click="$emit('eliminar', inventario.codeInv)">Eliminar</button></div></td>
                </tr>
            </tbody>
        </table>
    </div>
</template>
<script>
import axios from 'axios';
export default{
    data(){
        return{
            inventarios:[],

        };
    },
    methods:{
        obtenerInventarios(){
            axios.get("https://proyecto5-production-7426.up.railway.app/api/inventario/listar")
            .then((response)=>{

                this.inventarios=response.data;

            })
            .catch((error)=>{
                console.error("error al obtener la lista inventario",error)
            });
        },
    },

    mounted(){
        this.obtenerInventarios();
    }
}

</script>